// Handler is the type that all proxies need to implement to be called by the worker
// when a new client connection is created.  If there is an error ProxyConnFn must
// be nil. If there is no error ProxyConnFn must be set.  When Handler has
// returned, it is expected that the initial connection to the endpoint has been
// established.
// Updated to accept separate control and data contexts.
type Handler func(controlCtx context.Context, dataCtx context.Context, decryptFn DecryptFn, conn net.Conn, out *ProxyDialer, connId string, protoCtx *anypb.Any, rec RecordingManager) (ProxyConnFn, error)

func handleProxy(controlCtx context.Context, dataCtx context.Context, _ proxy.DecryptFn, conn net.Conn, out *proxy.ProxyDialer, connId string, _ *anypb.Any, _ proxy.RecordingManager) (proxy.ProxyConnFn, error) {
const op = "tcp.HandleProxy"
if conn == nil {
    return nil, errors.New(dataCtx, errors.InvalidParameter, op, "conn is nil")
}
if out == nil {
    return nil, errors.New(dataCtx, errors.InvalidParameter, op, "proxy dialer is nil")
}
if len(connId) == 0 {
    return nil, errors.New(dataCtx, errors.InvalidParameter, op, "connection id is empty")
}
remoteConn, err := out.Dial(dataCtx)
if err != nil {
    return nil, err
}
return func(ctx context.Context) {
    connWg := new(sync.WaitGroup)
    connWg.Add(2)
    go func() {
        defer connWg.Done()
        _, _ = io.Copy(conn, remoteConn)
        _ = conn.Close()
        _ = remoteConn.Close()
    }()
    go func() {
        defer connWg.Done()
        _, _ = io.Copy(remoteConn, conn)
        _ = remoteConn.Close()
        _ = conn.Close()
    }()
    connWg.Wait()
}, nil
}

